    "targets": [
        {
        "datasource": {
            "type": "grafana-postgresql-datasource",
            "uid": "w4ayEFP7k"
        },
        "editorMode": "code",
        "format": "time_series",
        "group": [],
        "hide": false,
        "metricColumn": "energy_efficiency_rating",
        "rawQuery": true,
        "rawSql": "    SELECT measurement.measurement_time AS \"time\",\n           pumpgroup.name AS \"Bombeo\",\n           measurement.instantaneous_flow AS \"Caudal\"\n      FROM wua_pumpgroupmeasurement measurement\nINNER JOIN wua_pumpgroup pumpgroup ON measurement.pumpgroup_id = pumpgroup.id\n     WHERE pumpgroup.name IN ($pumpgroup)\n       AND measurement.of_active_agriculturalseason\n  GROUP BY \"time\", pumpgroup.name, measurement.instantaneous_flow\n  ORDER BY \"time\"",
        "refId": "A",
        "select": [
            [
            {
                "params": [
                "method_progress_factor"
                ],
                "type": "column"
            }
            ]
